def _quantize_mse(im1, im2):
    """
    Mean square error, averaged over the RGB channels, between two images.
    Used by :py:meth:`~PIL.Image.Image.quantize` to evaluate ``error_threshold``.
    """
    from . import ImageChops, ImageStat

    diff = ImageChops.difference(im1.convert("RGB"), im2.convert("RGB"))
    stat = ImageStat.Stat(diff)
    return sum(rms ** 2 for rms in stat.rms) / len(stat.rms)


def _sort_quantized_palette(im, sort_palette):
    """
    Reorders the palette of a quantized 'P' mode image (and remaps its
    pixel data to match) by luminance, or by raw RGB value if
    ``sort_palette == "rgb"``.
    """
    used = [i for i, count in enumerate(im.histogram()) if count]
    if len(used) <= 1:
        return im

    palette = im.im.getpalette("RGB", "RGB")
    colors = {i: palette[i * 3 : i * 3 + 3] for i in used}

    if sort_palette == "rgb":
        key = colors.get
    else:
        def key(i):
            r, g, b = colors[i]
            return 0.299 * r + 0.587 * g + 0.114 * b

    dest_map = sorted(used, key=key)
    return im.remap_palette(dest_map)


